window.__QUIZ_DATA__=[{"id":"objective>Agricultural Science>2017>1","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"BASIC CONCEPTS : MEANING AND IMPORTANCE OF AGRICULTURE","question":"The branch of agriculture which deals with the production of fruits is called","images":[],"options":{"A":"pomology","B":"floriculture","C":"olericulture","D":"nematology"},"answer":"A","explanation":"Pomology is the branch of agriculture that deals with the cultivation, production, and study of fruits. Therefore, the correct answer is 'pomology'. Floriculture is the cultivation of flowers, olericulture is the cultivation of vegetables, and nematology is the study of nematodes (roundworms), none of which are specifically related to fruit production.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2017>2","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL FINANCE","question":"One advantage of cooperative farming is that it","images":[],"options":{"A":"allows farmers to have small and scattered plots","B":"enables individual farmers to acquire loans from the banks","C":"enables farmers to raise needed capital","D":"facilitates the use of local tools"},"answer":"C","explanation":"Cooperative farming is a farming whereby two or more people, a group of people, community etc. come together for the purpose of farming in other to make profit. One of the advantages of the cooperative farming is that it enables farmers to raise needed capital","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2017>3","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ECOLOGY : FACTORS AFFECTING LAND AVAILABILITY FOR AGRICULTURAL PURPOSE","question":"Which of the following statements is not a problem associated with land tenure system through inheritance?","images":[],"options":{"A":"Family members have small land buildings","B":"Family members have right to free use of land","C":"Non-family members cannot inherit land","D":"Farm mechanization is restricted"},"answer":"B","explanation":"Problem associated with land tenure system through inheritance are:  - family members have small land holdings (i.e it can be as a result of many children)  - Non-family members cannot inherit land   - mechanized farming is restricted due to small land holding     Family members having right to free use of land is not a problem associated with land tenure system by inheritance.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>4","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"A farmland measures 50 m x 50 m. Determine its area in hectares","images":[],"options":{"A":"25 ha","B":"2.5 ha","C":"0.25 ha","D":"0.025 ha"},"answer":"C","explanation":"Given that   farmland = 50m x 50m   \u2234 The Area of farmland = 50 x 50   = 2500 m2  In hectares   Recall that, 1 hectare = 10,000 m2  x hectares = 2500m2   x=250010000=0.25ha","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>5","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"Study the illustration of farm implements below and use it to answer question below      The part of the implements labelled I is called","images":["data:image/png;base64,"],"options":{"A":"disc","B":"beam","C":"disc scraper","D":"plough share"},"answer":"B","explanation":"The part labelled I - beam. In a plough, the beam is the main structural part that connects the various components of the plough, such as the mouldboard, ploughshare, and handles, to the point of attachment with the draught animal or tractor.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>6","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"Study the illustration of farm implements below and use it to answer question below    The part of the implements which makes horizontal cuts into the soil and uproots weeds is labelled as","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"D","explanation":"The part labelled IV ( ) make horizontal cuts into the soil and uproots weeds","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>7","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"Study the illustration of farm implements below and use it to answer question below    The function of the part labelled II is to","images":["data:image/png;base64,"],"options":{"A":"make horizontal cuts into the soil","B":"make vertical cuts into the soil","C":"roll over obstacles","D":"remove soil from the disc"},"answer":"D","explanation":"The part labelled II ( ) helps to remove soil from the disc","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>8","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"Study the illustration of farm implements below and use it to answer question below    Which of the labelled parts provides balance to the implement?","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"C","explanation":"The part labelled III provides balance to the implement","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>9","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"A farming system in which different types of crops are grown in succession, in a definite order on the same piece of land is termed","images":[],"options":{"A":"mixed farming","B":"land rotation","C":"continuous cropping","D":"crop rotation"},"answer":"D","explanation":"Crop rotation  is a farming system in which different type of crops are grown in succession, in a definite order on the same piece of land","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>10","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"Land use for agriculture in West Africa is influenced by the following factors except","images":[],"options":{"A":"population density","B":"topography","C":"fallowing","D":"climate"},"answer":"C","explanation":"Population density, Topography, Climate condition etc. are factors affecting land use for agriculture in West Africa. Fallowing is not a factor but a system of farming in West Africa","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>11","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ECOLOGY : FACTORS AFFECTING LAND AVAILABILITY FOR AGRICULTURAL PURPOSE","question":"A social factor which affects land availability and use is","images":[],"options":{"A":"temperature","B":"soil pH","C":"light intensity and duration","D":"culture of the people"},"answer":"D","explanation":"The culture of the people is a social factor that affects land availability and use. This is because different cultures have different beliefs and practices that can influence how land is used. For example, some cultures may have certain areas of land that are considered sacred and therefore cannot be used for agriculture.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>12","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS AFFECTING CROP AND ANIMAL DISTRIBUTION AND PRODUCTION","question":"The following are climatic factors affecting agricultural production except","images":[],"options":{"A":"rainfall","B":"relative humidity","C":"temperature","D":"topography"},"answer":"D","explanation":"Rainfall, Relative humidity, temperature etc., are climatic factors affecting agricultural production, while topography is an edaphic factor","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>13","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"CROP PROTECTION : PESTS OF CROPS","question":"Predators are used by farmers to","images":[],"options":{"A":"control pests","B":"induce flowering in plants","C":"protect the soil","D":"hasten fruit ripening"},"answer":"A","explanation":"The use of the predator of a particular pests in one of the ways farmers used to control pests. This process is called biological control of pest.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2017>14","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ROCK FORMATION","question":"Which of the following agents is not associated with chemical weathering?","images":[],"options":{"A":"Oxidation","B":"Pressure","C":"Hydrolysis","D":"Carbonation"},"answer":"B","explanation":"Agents associated with chemical weathering are   - Oxidation - Hydrolysis - Carbonation   pressure is not an agent of chemical weathering","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>15","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"Which of the following statements is not correct about soil texture?","images":[],"options":{"A":"Soils with fine particles have higher water-holding capacity than coarse soils","B":"Fine-textured soils are warm soils and coarse-textured soils are cool soils","C":"The effect of leaching in coarse-textured soils is greater than that in fine-textured soils","D":"Fine-textured soils have higher nutrient-holding capacity than coarse-texture soils"},"answer":"B","explanation":"Soil texture refers to the relative proportion of sand, silt, and clay particles in a mass of soil. The statement 'Fine-textured soils are warm soils and coarse-textured soils are cool soils' is incorrect. In reality, coarse-textured soils (sandy soils) warm up more quickly than fine-textured soils (clay soils) because they have larger particles and less water-holding capacity. The larger particles allow for more air spaces which can fill with heat.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>16","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Inhibition of root and fruit formation are deficiency symptoms of","images":[],"options":{"A":"iron","B":"nitrogen","C":"chlorine","D":"phosphorus"},"answer":"D","explanation":"Phosphorus is a nutrient that plays a key role in the formation of DNA, RNA, and ATP, which are essential for energy transfer and storage in plants. It is also crucial for root development and fruit formation. Therefore, a deficiency in phosphorus can lead to inhibition of root and fruit formation.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>17","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"In the carbon cyle, carbon dioxide is used by crops for","images":[],"options":{"A":"photosynthesis","B":"transpiration","C":"decomposition","D":"respiration"},"answer":"A","explanation":"In the carbon cycle, plants absorb carbon dioxide from the atmosphere during photosynthesis. This process converts carbon dioxide and sunlight into oxygen and glucose, which the plant uses for growth and energy. Therefore, carbon dioxide is used by crops for photosynthesis.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2017>18","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ECOLOGY : IRRIGATION","question":"Flood irrigation is used for the cultivation of","images":[],"options":{"A":"water melon","B":"swamp rice","C":"oil palm","D":"coconut"},"answer":"B","explanation":"Flood irrigation is a method of irrigation where water is poured over the land surface and allowed to flow over the farm. This method is commonly used for crops that grow in a wet environment like rice. Therefore, the correct answer is swamp rice.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>19","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ECOLOGY : DRAINAGE","question":"The presence of excess water in the colloids of soil particles is known as","images":[],"options":{"A":"drainage","B":"waterlogging","C":"irrigation","D":"leaching"},"answer":"B","explanation":"Waterlogging refers to the saturation of soil with water. Soil may be regarded as waterlogged when it is nearly saturated with water much of the time such that its air phase is restricted and anaerobic conditions prevail. Therefore, the correct answer is waterlogging.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>20","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"Study the illustration below and use it to answer question     The crop roots illustrated above are that of a","images":["data:image/png;base64,"],"options":{"A":"legume","B":"cereal","C":"tuber","D":"spice"},"answer":"A","explanation":"The roots in the text as the presence of nodules which helps in nitrogen fixation in plant. Legumes have possess root modules in its root","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2017>21","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM PLANNING","question":"If rows of crops are spaced 1.0 m apart with one seed sown per stand, determine the spacing between stands to obtain population of 40,000 plants per hectare","images":[],"options":{"A":"0.25 m","B":"0.45 m","C":"0.50 m","D":"1.00 m"},"answer":"A","explanation":"40,000 plants per hectare means 4 plant per 1 square metre.  Therefore the spacing between stands = 1/4 = 0.25m","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>22","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"The correct sequence of pre-planting operation is","images":[],"options":{"A":"clearing \u2192stumping \u2192 ploughing \u2192 harrowing","B":"stumping \u2192 ploughing \u2192harrowing \u2192clearing","C":"bulldozing \u2192harrowing \u2192stumping \u2192 ploughing","D":"clearing \u2192bulldozing \u2192 stumping \u2192 harrowing"},"answer":"A","explanation":"The correct sequence of pre-planting operation is clearing \u2192stumping \u2192 ploughing \u2192 harrowing. This is because clearing involves removing the vegetation cover, stumping involves removing the tree stumps, ploughing involves turning the soil to prepare it for planting, and harrowing involves breaking up and smoothing out the soil. This sequence ensures that the land is properly prepared for planting.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>23","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"CROP PRODUCTION : CROP IMPROVEMENT","question":"Heat treatment of oil palm seeds before sowing helps to","images":[],"options":{"A":"mobilize nutrients for the embryo","B":"harden the mesocarp","C":"break embryo dormancy","D":"improve disease resistance"},"answer":"C","explanation":"Heat treatment of oil palm seeds before sowing helps to break embryo dormancy. This is because heat treatment can help to overcome the physical or physiological barriers that prevent the seed from germinating, thus breaking the embryo dormancy.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>24","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ECOLOGY : AGRO-ALLIED INDUSTRIES AND RELATIONSHIP BETWEEN AGRICULTURE AND INDUSTRY","question":"Imported plants are expected to be","images":[],"options":{"A":"vaccinated","B":"improved upon","C":"treated","D":"quarantined"},"answer":"D","explanation":"Imported plants are expected to be quarantined. This is because quarantine is a measure used to prevent the spread of pests and diseases that may be present in the imported plants. The plants are kept under observation for a certain period of time to ensure that they are free from pests and diseases before they are released.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>25","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"CROP PRODUCTION : CROP IMPROVEMENT","question":"A breeding method which involves the production of heterozygous populations from homozygous lines is","images":[],"options":{"A":"breeding","B":"introduction","C":"selection","D":"hybridization"},"answer":"D","explanation":"Hybridization is a breeding method which involves the production of heterozygous populations from homozgous lines","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>26","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"FORESTRY : FOREST MANAGEMENT","question":"A raw material that could be obtained from the forest is","images":[],"options":{"A":"margarine","B":"honey","C":"mutton","D":"butter"},"answer":"B","explanation":"A raw material that could be obtained from the forest is honey. Honey is a natural product produced by bees and can be harvested from wild bees in forests.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>27","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Which of the following methods of plants propagation is limited to plants which roots easily?","images":[],"options":{"A":"Grafting and cutting","B":"Layering and cutting","C":"Budding and layering","D":"Grafting and layering"},"answer":"B","explanation":"The method of plant propagation that is limited to plants which root easily is layering and cutting. Both these methods involve the use of plant parts that can easily develop roots. In layering, a stem is bent and covered with soil while still attached to the parent plant until roots develop. In cutting, a piece of the plant is cut off and planted to develop roots.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>28","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"ORNAMENTAL PLANTS :","question":"Which of the following practices is not a way of maintaining ornamental plants?","images":[],"options":{"A":"Pruning","B":"Weeding","C":"Watering","D":"Harvesting"},"answer":"D","explanation":"Ways of maintaining ornamental plants are:  - Pruning - watering - weeding   Harvesting is not a way of maintaining ornamental plants","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>29","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"Which of the following pairs of diseases attack coffee?","images":[],"options":{"A":"Mosaic and smut","B":"Smut and midge","C":"Rust and mosaic","D":"Rust and leaf spot"},"answer":"C","explanation":"Rust and mosaic are diseases that attack coffee. Rust is a type of fungal disease that affects coffee leaves causing them to fall off prematurely. Mosaic is a viral disease that causes a mosaic-like pattern on the leaves of the coffee plant, hence the name. Both diseases can significantly reduce coffee yield.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>30","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"CROP PROTECTION : PESTS OF CROPS","question":"Insect-pests of crops could be controlled by","images":[],"options":{"A":"cover cropping","B":"mulching","C":"crop rotation","D":"organic manuring"},"answer":"C","explanation":"Insect-pests of crops could be controlled by crop rotation. Crop rotation is a method of pest control that involves changing the type of crop grown in a particular field from season to season. This practice disrupts the life cycle of pests and can help to reduce their numbers. The other options listed, such as cover cropping, mulching, and organic manuring, are primarily used for soil conservation and fertility management, not pest control.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>31","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"CROP PROTECTION : PESTS OF CROPS","question":"Which of the following insect-pests does not attack cotton?","images":[],"options":{"A":"Aphid","B":"Cotton stainer","C":"Weevil","D":"Pink bollworm"},"answer":"C","explanation":"Weevils are not known to attack cotton. They are more commonly associated with stored grain products. Aphids, Cotton stainers, and Pink bollworms are all pests that can cause significant damage to cotton crops.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2017>32","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"CROP PROTECTION : WEEDS","question":"Which of the following practices is an example of a cultural weed control method?","images":[],"options":{"A":"Use of insects","B":"Mowing","C":"Application of herbicides","D":"Mulching"},"answer":"D","explanation":"Use of insect - biological weed control   Application of herbicides - chemical weed control   Mulching - cultural weed control","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2017>33","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"The diagram below illustrates the digestive track of a farm animal   Study it and use it to answer questions 33, 34 and 35.    The farm animal associated with the digestive track illustrated above is","images":["data:image/png;base64,"],"options":{"A":"turkey","B":"cattle","C":"pig","D":"goat"},"answer":"C","explanation":"Pig. The digestive system of a pig is well-adapted for processing a variety of food, including plant materials and animal products. It consists of the following key components:    Mouth: Pigs have a strong jaw and teeth for chewing food, and saliva contains enzymes that begin the digestion of carbohydrates.    Esophagus: A muscular tube that transports food from the mouth to the stomach.    Stomach: Pigs have a simple stomach with three regions (glandular, cardiac, and pyloric) that secrete digestive acids and enzymes, breaking down food further.    Small Intestine: Comprising the duodenum, jejunum, and ileum, the small intestine is where most nutrient absorption occurs. Enzymes from the pancreas and bile from the liver aid in digestion.    Cecum: A small pouch that aids in the fermentation of fibrous material, though pigs are not hindgut fermenters like some other animals.    Large Intestine: Responsible for absorbing water and electrolytes, the large intestine leads to the rectum.    Rectum: The final part of the digestive tract, where waste is stored before being excreted.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>34","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"Digestion of protein starts in the part labelled","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"A","explanation":"Digestion of protein starts in the part labelled I (stomach) where we had the secretion of pepsin which convert protein to peptodes/polypetide","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>35","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"Which of the following enzymes is not secreted by the part labelled III?","images":["data:image/png;base64,"],"options":{"A":"Pepsin","B":"Amylase","C":"Lipase","D":"Trypsin"},"answer":"A","explanation":"The part labelled III is the duodenum, enzymes secreted are Amylase Lipase and Trypsin. Pepsin is secreted in the stomach","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>36","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"Study the illustrated poultry equipment and use them to answer question 36, 37 and 38.    Which of the illustrated equipment is not used in a brooder house?","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"A","explanation":"I - Egg candler is not used in brooder house. An egg candler is a device used to assess the quality of eggs, particularly during incubation, by shining a bright light through them. This allows for the visualization of the embryo's development and the detection of any defects or infertile eggs.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>37","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"Which of the following equipment could be used in place of the equipment labelled II in the management of chicks?","images":["data:image/png;base64,"],"options":{"A":"Incubator","B":"Feeder","C":"Electric bulb","D":"Egg candler"},"answer":"C","explanation":"The equipment II - Lantern serves a source of light for the chick, the electric bulb can also be used in place of it in the management of chicks.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>38","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"Which quality of eggs is associated with the equipment labelled I?","images":["data:image/png;base64,"],"options":{"A":"Size","B":"Fertility","C":"Colour","D":"Price"},"answer":"B","explanation":"The equipment labelled I (egg candler) helps to check for the fertility of the egg.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>39","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"Study the illustration below and use it to answer question.    What is the name given to the identification method illustrated above?","images":["data:image/jpeg;base64,"],"options":{"A":"Tagging","B":"Neck chaining","C":"Ear notching","D":"Branding"},"answer":"D","explanation":"Branding is the act of giving sign, number, etc. to animal in order to determine the number of the animal or to identify them.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>40","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"A farmer collects 800 eggs from a laying stock of 1,200 birds per day. Determine the laying percentage of the stock.","images":[],"options":{"A":"150%","B":"67%","C":"50%","D":"33%"},"answer":"B","explanation":"Given that,  No. of egg collected - 800   No. of layering birds - 1,200   % of layering = ?  %layering=No. of egg collectedNo. of layering birdx100    =8001200x100  = 67%","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>41","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"By-products of livestock used as feed ingredients in poultry ration include","images":[],"options":{"A":"hides and hoofs","B":"blood and bones","C":"feathers and fur","D":"skin and bones"},"answer":"B","explanation":"By-products of livestock that can be used as feed ingredients in poultry ration include blood and bones. These by-products are rich in protein and minerals which are essential for the growth and development of poultry. Hides, hoofs, feathers, fur, and skin are not typically used in poultry feed due to their low nutritional value and difficulty in digestion.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>42","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL IMPROVEMENT","question":"The practice of mating closely related animals is called","images":[],"options":{"A":"cross breeding","B":"hybridization","C":"in-breeding","D":"out-breeding"},"answer":"C","explanation":"Inbreeding is the practice of mating closely related animals in other to maintain the desired characteristics","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2017>43","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"Study the farm animal parasite illustrated below and use it to answer question 43 and 44.    The part labelled I, II and III form the","images":["data:image/png;base64,"],"options":{"A":"proglottide","B":"rostellum","C":"sucker","D":"scolex"},"answer":"D","explanation":"The part labelled I (Rosetellum), II(Hook), III (Sucker) are form the scolex.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>44","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"The parasite illustrated in the diagram above obtains nutrients from the host through","images":["data:image/png;base64,"],"options":{"A":"osmosis","B":"diffusion","C":"capillarity","D":"egestion"},"answer":"B","explanation":"It obtains nutrients from the host through diffusion (It is as a result of its large surface Area to volume ratio)","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>45","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"ANIMAL PRODUCTION : AQUACULTURE","question":"In fish farming, Clarias is introduced to a pond stocked with Tilapia in order to","images":[],"options":{"A":"regulate the population of Tilapia","B":"compete with Tilapia for feed","C":"check pests in the pond water","D":"regulate the turbidity of the pond water"},"answer":"A","explanation":"In fish farming, Clarias (a species of catfish) is often introduced to a pond stocked with Tilapia in order to regulate the population of Tilapia. Clarias is a predatory fish that feeds on smaller fish, including young Tilapia, thereby controlling their population. The other options are incorrect as Clarias does not compete with Tilapia for feed, does not check pests in the pond water, and does not regulate the turbidity of the pond water.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2017>46","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF DEMAND","question":"The demand for agricultural produce is generally","images":[],"options":{"A":"infinite","B":"inelastic","C":"unitary","D":"static"},"answer":"B","explanation":"The demand for agricultural produce is generally inelastic. This is because agricultural products are often necessities, and their demand does not change significantly with changes in price. In economics, inelastic demand refers to a situation where the demand for a product does not change significantly when its price changes.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2017>47","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL FINANCE","question":"Subsidies are given to farmers in the form of","images":[],"options":{"A":"reduced prices of inputs","B":"provision of social infrastructure","C":"high tariff on imported inputs","D":"short term loans"},"answer":"A","explanation":"Subsidies are given to farmers in the form of reduced prices of inputs. This is done to lower the cost of production for farmers, encourage more production, and make agricultural products more affordable for consumers. A subsidy is a form of financial aid or support extended to an economic sector to promote economic and social policy.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2017>48","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF SUPPLY","question":"Use the table below to answer question 48 Demand and Supply Schedules for Mangoes   Price of fruit (Le) Supply (No. of baskets) Demand (No. of baskets)1 000.00 10 602 000.00 20 50 3 000.00 30 404 000.00 40 305 000.00 50 206 000.00 60 10    At a unit price of Le 1,000.00, what will be the excess demand over supply of mangoes?","images":[],"options":{"A":"50 baskets","B":"40 baskets","C":"20 baskets","D":"10 baskets"},"answer":"A","explanation":"At a unit price of Le 1,000.00, the supply of mangoes is 10 baskets while the demand is 60 baskets. Therefore, the excess demand over supply is 60 - 10 = 50 baskets. Excess demand occurs when the quantity demanded of a good or service exceeds its supply in a market.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2017>49","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : MARKETING OF AGRICULTURAL PRODUCE","question":"Which of the following agents is not involved in agricultural marketing?","images":[],"options":{"A":"Commodity boards","B":"Money lenders","C":"Retailers","D":"Middlemen"},"answer":"B","explanation":"Money lenders are not directly involved in agricultural marketing. They provide loans to farmers or traders but do not participate in the buying or selling of agricultural products. Commodity boards, retailers, and middlemen, on the other hand, are all involved in the marketing process. Commodity boards regulate the production and sale of certain commodities, retailers sell products to consumers, and middlemen act as intermediaries between producers and retailers or consumers.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2017>50","subject":"Agricultural Science","year":"2017","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL EXTENSION","question":"Agricultural extension teaching methods are classified on the basis of","images":[],"options":{"A":"teaching materials","B":"topics to be taught","C":"attitude of farmers","D":"audience size"},"answer":"D","explanation":"Agricultural extension teaching methods are classified based on the audience size. This is because the size of the audience determines the most effective way to deliver the information. For example, a large audience may require a lecture or demonstration, while a small audience may be better suited to a discussion or hands-on activity. The teaching materials, topics to be taught, and attitude of farmers are all important considerations in agricultural extension, but they do not form the basis for classifying teaching methods.","marks":"1","difficulty":"2"}];